import { existsSync, mkdirSync, writeFileSync, copyFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));

const iconsDir = join(__dirname, 'src-tauri', 'icons');
if (!existsSync(iconsDir)) mkdirSync(iconsDir, { recursive: true });

const icons = {
  '32x32.png': '',
  '128x128.png': '',
  '128x128@2x.png': '',
  'icon.ico': '',
  'tray-icon.png': 'iVBORw0KGgoAAAANSUhEUgAAACAAAAAgCAYAAABzenr0AAAARUlEQVR42mNgGAVkgP///z/DhYe+A/AZTg08dBxAq2gbdcDQcwC1Et1oFIymgdEoGE0Do1Ew6oBRBww9B4zcVvEoGHEAADE+nTgyLUDtAAAAAElFTkSuQmCC',
};

for (const [name, b64] of Object.entries(icons)) {
  const dest = join(iconsDir, name);
  if (!existsSync(dest)) {
    writeFileSync(dest, Buffer.from(b64, 'base64'));
    console.log('Created icon:', name);
  }
}

const icns = join(iconsDir, 'icon.icns');
if (!existsSync(icns)) {
  copyFileSync(join(iconsDir, '128x128@2x.png'), icns);
  console.log('Created icon.icns placeholder');
}

console.log('Icons ready!');
